#!/usr/bin/env python3
import argparse, datetime as dt, json, os, sqlite3, subprocess
from typing import Any
DB_DEFAULT='./data/bonelord_operational.sqlite'; DISCORD_CHANNEL='0'; DISCORD_SCRIPT='~/.codex/skills/discord/scripts/discord_skill.py'
def now(): return dt.datetime.now(dt.UTC).replace(microsecond=0).isoformat().replace('+00:00','Z')
def j(x:Any): return json.dumps(x,ensure_ascii=False,sort_keys=True)
def send(msg):
    if os.path.exists(DISCORD_SCRIPT): subprocess.run(['/bin/zsh','-lc',f"source ~/.env 2>/dev/null || true; python {DISCORD_SCRIPT} send --channel {DISCORD_CHANNEL} --message {json.dumps(msg)}"],check=False)
def create(cur):
    cur.executescript('''
    create table if not exists non_circular_lane_result_runs(run_id integer primary key autoincrement,created_at text not null,lane_count integer not null,pass_count integer not null,blocked_count integer not null,decision text not null,next_action text not null,payload_json text not null);
    create table if not exists non_circular_lane_result_items(run_id integer not null,lane_id text not null,status text not null,result_summary text not null,accepted_anchors_json text not null,blocked_reason text not null,next_action text not null,evidence_json text not null,primary key(run_id,lane_id));''')
def main():
    ap=argparse.ArgumentParser(); ap.add_argument('--db',default=DB_DEFAULT); ap.add_argument('--discord',action='store_true'); args=ap.parse_args(); con=sqlite3.connect(args.db); cur=con.cursor(); create(cur)
    lanes=[
      dict(lane_id='EXACT_EXTERNAL_MEANING_SOURCE_SEARCH',status='PARTIAL_ANCHOR_ONLY_NO_BOOK_PROMOTION',result_summary='Official/provenance anchors found only for 1=Tibia/context, 486486=Wrinkled Bonelord name, 469=language label, 3478 weak old Beholder label; no phrase/book translation.',accepted_anchors=['1','486486','469','3478_WEAK_ENTITY_LABEL'],blocked_reason='No exact source-attested phrase/book meaning strong enough for semantic promotion.',next_action='Use anchors as context/holdout only; continue searching only for exact sequence+meaning provenance.',evidence={'urls':['https://tibia.fandom.com/wiki/A_Wrinkled_Bonelord/Transcripts','https://tibia.fandom.com/wiki/469','https://www.tibiaqa.com/25010/what-is-the-name-of-a-wrinkled-bonelord-in-language-469','https://www.tibiawiki.com.br/wiki/Bonelord_%28Nostalgia%29']}),
      dict(lane_id='BASE_N_WITH_AUTHENTIC_TIBIA_CHARSET',status='BLOCKED_LOGIN_ONLY_OR_UNVERIFIED',result_summary='Public order mechanics found via YATC/pic-editor, but authentic charset.zip/Tibia.pic artifact unavailable or gated; generic sweeps failed readability.',accepted_anchors=[],blocked_reason='Need downloadable authentic old Tibia PIC charset/order artifact; OTLand attachment inaccessible.',next_action='Reopen only if charset.zip or authentic Tibia.pic is obtained locally and can be extracted.',evidence={'urls':['https://otland.net/threads/decoding-469-stephan-voglers-files-im-in-need-of-a-pic-extractor-editor.303637/#post-2795682','https://github.com/opentibia/yatc','https://github.com/Elime1/pic-editor']}),
      dict(lane_id='RAW_DIGIT_GENERATIVE_MODEL_WITH_HOLDOUTS',status='STRUCTURAL_SIGNAL_NO_SEMANTIC_PROMOTION',result_summary='00 contexts pass shuffle control and recurrent segments are explained by existing functional families; no new semantic candidate.',accepted_anchors=[],blocked_reason='Signal is structural boundary support only; no lexical meaning.',next_action='Use 00 as feature in future structural scoring, not as translation.',evidence={'zero_shuffle':'ZERO_CONTEXTS_PASS_SHUFFLE_CONTROL_STRUCTURAL_SIGNAL','zero_segments':'ZERO_BOUNDARY_SEGMENTS_ALL_EXPLAINED'})]
    pass_count=sum(1 for l in lanes if l['status'].startswith('PASS')); blocked_count=sum(1 for l in lanes if 'BLOCKED' in l['status'] or 'NO_' in l['status'] or 'STRUCTURAL' in l['status'])
    cur.execute('insert into non_circular_lane_result_runs(created_at,lane_count,pass_count,blocked_count,decision,next_action,payload_json) values (?,?,?,?,?,?,?)',(now(),len(lanes),pass_count,blocked_count,'NON_CIRCULAR_BATCH_NO_SEMANTIC_PROMOTION','prioritize artifact acquisition or exact external meaning; keep gloss at 0',j({'lanes':lanes})))
    run_id=cur.lastrowid
    for l in lanes: cur.execute('insert into non_circular_lane_result_items(run_id,lane_id,status,result_summary,accepted_anchors_json,blocked_reason,next_action,evidence_json) values (?,?,?,?,?,?,?,?)',(run_id,l['lane_id'],l['status'],l['result_summary'],j(l['accepted_anchors']),l['blocked_reason'],l['next_action'],j(l['evidence'])))
    con.commit(); print(json.dumps({'run_id':run_id,'decision':'NON_CIRCULAR_BATCH_NO_SEMANTIC_PROMOTION','lane_count':len(lanes),'pass_count':pass_count,'blocked_count':blocked_count},ensure_ascii=False))
    if args.discord: send('\n'.join([f'[469][non-circular-results][run={run_id}] batch de hipóteses não-circulares consolidado','externo: só anchors pequenos/contextuais; sem tradução de livro/frase','charset: bloqueado por artifact/login; varredura genérica rejeitada','raw-digit: 00 é sinal estrutural, não semântico','decisão: sem promoção semântica; manter gloss=0 e buscar artifact/fonte exata.']))
if __name__=='__main__': main()
